12. Generate SINGLE PASS shaders only.
`;

export const generateShader = async (prompt: string, currentCode?: string): Promise<string> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let finalPrompt = prompt;
  if (currentCode) {
    finalPrompt = `Refine this existing ISF shader based on the request: "${prompt}".\n\nExisting Code:\n${currentCode}`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Good balance of speed and code logic
      contents: finalPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.8, // Slightly creative
        maxOutputTokens: 8192, // Allow for long shader code
      },
    });

    let text = response.text || "";

    // Cleanup markdown if present
    text = text.replace(/^```glsl\s*/i, '').replace(/^```\s*/, '').replace(/```$/, '');

    return text;
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

