import { useState, useEffect, useRef, useCallback } from 'react';

export const useMedia = () => {
  const [isWebcamActive, setIsWebcamActive] = useState(false);
  const [isMicActive, setIsMicActive] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [audioVolume, setAudioVolume] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(document.createElement('video'));
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);
  const animationFrameRef = useRef<number>();

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  // Webcam Logic
  const toggleWebcam = useCallback(async () => {
    if (isWebcamActive) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream?.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
      setIsWebcamActive(false);
    } else {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
        videoRef.current.srcObject = stream;
        videoRef.current.play();
        setIsWebcamActive(true);
      } catch (e) {
        console.error("Failed to access webcam", e);
        alert("Could not access webcam. Please check permissions.");
      }
    }
  }, [isWebcamActive]);

  // Microphone Logic
  const toggleMic = useCallback(async () => {
    if (isMicActive) {
      audioContextRef.current?.close();
      audioContextRef.current = null;
      setIsMicActive(false);
      setAudioVolume(0);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    } else {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioContextRef.current = audioCtx;

        const analyser = audioCtx.createAnalyser();
        analyser.fftSize = 64; // Low resolution for simple volume
        analyser.smoothingTimeConstant = 0.8;
        analyserRef.current = analyser;

        const source = audioCtx.createMediaStreamSource(stream);
        source.connect(analyser);

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);
        dataArrayRef.current = dataArray;

        const updateVolume = () => {
          if (!analyserRef.current || !dataArrayRef.current) return;
          analyserRef.current.getByteFrequencyData(dataArrayRef.current);

          let sum = 0;
          for(let i = 0; i < dataArrayRef.current.length; i++) {
            sum += dataArrayRef.current[i];
          }
          const avg = sum / dataArrayRef.current.length;
          setAudioVolume(avg / 255.0); // Normalize 0-1

          animationFrameRef.current = requestAnimationFrame(updateVolume);
        };

        setIsMicActive(true);
        updateVolume();

      } catch (e) {
        console.error("Failed to access microphone", e);
        alert("Could not access microphone.");
      }
    }
  }, [isMicActive]);

  // Recording Logic
  const startRecording = useCallback((canvas: HTMLCanvasElement) => {
    try {
      const stream = canvas.captureStream(30); // 30 FPS

      // If mic is active, try to add audio track? 
      // Complexity: Syncing might be off, let's stick to video only for now to keep it simple
      // or just mix it if feasible.

      const options = { mimeType: 'video/webm;codecs=vp9' };
      if (!MediaRecorder.isTypeSupported(options.mimeType)) {
          options.mimeType = 'video/webm'; // Fallback
      }

      const recorder = new MediaRecorder(stream, options);
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'video/webm' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Aether_Rec_${Date.now()}.webm`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      };

      recorder.start();
      setIsRecording(true);
    } catch (e) {
      console.error("Failed to start recording", e);
    }
  }, []);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  }, [isRecording]);

  useEffect(() => {
    return () => {
        // Cleanup
        if (isWebcamActive) {
            const stream = videoRef.current.srcObject as MediaStream;
            stream?.getTracks().forEach(t => t.stop());
        }
        if (audioContextRef.current) audioContextRef.current.close();
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    }
  }, []);

  return {
    videoElement: videoRef.current,
    isWebcamActive,
    toggleWebcam,
    isMicActive,
    toggleMic,
    audioVolume,
    isRecording,
    startRecording,
    stopRecording
  };
};

import React from 'react';
import { ISFInput, ISFMetadata, UniformValues } from '../types';
import { Camera, Image as ImageIcon, Sparkles } from 'lucide-react';

interface ControlsProps {
  metadata: ISFMetadata | null;
  values: UniformValues;
  sources: Record<string, string>; // 'noise', 'webcam', or blob URL
  onChange: (name: string, value: any) => void;
  onSourceChange: (name: string, source: string) => void;
  onImageUpload: (name: string, file: File) => void;
}

const Controls: React.FC<ControlsProps> = ({ 
    metadata, 
    values, 
    sources, 
    onChange, 
    onSourceChange,
    onImageUpload
}) => {
  if (!metadata || !metadata.INPUTS || metadata.INPUTS.length === 0) {
    return <div className="text-gray-500 text-sm italic p-4">No interactive parameters found.</div>;
  }

  return (
    <div className="space-y-4 p-4">
      {metadata.INPUTS.map((input) => {
        const currentValue = values[input.NAME] !== undefined ? values[input.NAME] : input.DEFAULT;

        if (input.TYPE === 'image') {
            const currentSource = sources[input.NAME] || 'noise';
            return (
                <div key={input.NAME} className="space-y-2 border border-gray-800 p-2 rounded bg-gray-800/20">
                    <label className="text-xs text-gray-400 block">{input.LABEL || input.NAME}</label>
                    <div className="flex gap-1">
                        <button 
                            onClick={() => onSourceChange(input.NAME, 'noise')}
                            className={`flex-1 p-2 rounded text-xs flex flex-col items-center gap-1 transition-colors ${currentSource === 'noise' ? 'bg-cyan-900/50 text-cyan-200 border border-cyan-700' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
                        >
                            <Sparkles size={14} />
                            <span>Noise</span>
                        </button>
                        <button 
                            onClick={() => onSourceChange(input.NAME, 'webcam')}
                            className={`flex-1 p-2 rounded text-xs flex flex-col items-center gap-1 transition-colors ${currentSource === 'webcam' ? 'bg-red-900/50 text-red-200 border border-red-700' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
                        >
                            <Camera size={14} />
                            <span>Webcam</span>
                        </button>
                        <label className={`flex-1 p-2 rounded text-xs flex flex-col items-center gap-1 cursor-pointer transition-colors ${currentSource.startsWith('blob') ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}>
                            <ImageIcon size={14} />
                            <span>Image</span>
                            <input 
                                type="file" 
                                accept="image/*" 
                                className="hidden" 
                                onChange={(e) => {
                                    if(e.target.files?.[0]) {
                                        onImageUpload(input.NAME, e.target.files[0]);
                                    }
                                }}
                            />
                        </label>
                    </div>
                </div>
            )
        }

        if (input.TYPE === 'float') {
          return (
            <div key={input.NAME} className="space-y-1">
              <div className="flex justify-between text-xs text-gray-400">
                <label>{input.LABEL || input.NAME}</label>
                <span>{typeof currentValue === 'number' ? currentValue.toFixed(2) : currentValue}</span>
              </div>
              <input
                type="range"
                min={input.MIN ?? 0.0}
                max={input.MAX ?? 1.0}
                step={0.01}
                value={typeof currentValue === 'number' ? currentValue : 0}
                onChange={(e) => onChange(input.NAME, parseFloat(e.target.value))}
                className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-cyan-500"
              />
            </div>
          );
        }

        if (input.TYPE === 'bool') {
          return (
            <div key={input.NAME} className="flex items-center justify-between">
              <label className="text-sm text-gray-300">{input.LABEL || input.NAME}</label>
              <button
                onClick={() => onChange(input.NAME, !currentValue)}
                className={`w-10 h-5 rounded-full relative transition-colors ${
                  currentValue ? 'bg-cyan-600' : 'bg-gray-700'
                }`}
              >
                <div
                  className={`absolute top-1 left-1 w-3 h-3 bg-white rounded-full transition-transform ${
                    currentValue ? 'translate-x-5' : ''
                  }`}
                />
              </button>
            </div>
          );
        }

        if (input.TYPE === 'long' && input.VALUES && input.LABELS) {
            // Dropdown (Select)
            return (
                <div key={input.NAME} className="space-y-1">
                    <label className="text-xs text-gray-400">{input.LABEL || input.NAME}</label>
                    <select 
                        value={currentValue}
                        onChange={(e) => onChange(input.NAME, parseInt(e.target.value))}
                        className="w-full bg-gray-800 border border-gray-700 text-gray-300 text-sm rounded-md p-2 focus:ring-cyan-500 focus:border-cyan-500"
                    >
                        {input.VALUES.map((val, idx) => (
                            <option key={val} value={val}>
                                {input.LABELS![idx]}
                            </option>
                        ))}
                    </select>
                </div>
            )
        }

        // Color (Simple approximation)
        if (input.TYPE === 'color') {
             // Convert vec4 array [r,g,b,a] to hex for input type=color
             // This is a basic implementation
             return (
                 <div key={input.NAME} className="space-y-1">
                      <label className="text-xs text-gray-400">{input.LABEL || input.NAME}</label>
                      <div className="flex gap-2">
                         <div className="w-full h-8 rounded bg-gray-700 flex items-center justify-center text-xs text-gray-500">
                             Color Picker Placeholder
                         </div>
                      </div>
                 </div>
             )
        }

        return null;
      })}
    </div>
  );
};

