            >
                <Download size={16} />
                <span className="hidden sm:inline">Export</span>
            </button>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex-1 flex overflow-hidden">

        {/* Left Sidebar */}
        <div className="w-full md:w-[360px] lg:w-[420px] flex flex-col border-r border-gray-800 bg-[#0a0a0a] overflow-hidden">

            {/* Sidebar Tabs */}
            <div className="flex border-b border-gray-800">
                <button 
                    onClick={() => setActiveTab('create')}
                    className={`flex-1 py-3 text-[10px] font-bold uppercase tracking-wider flex items-center justify-center gap-2 transition-colors ${
                        activeTab === 'create' 
                        ? 'bg-[#0a0a0a] text-cyan-500 border-b-2 border-cyan-500' 
                        : 'bg-[#050505] text-gray-500 hover:text-gray-300 hover:bg-[#0a0a0a]'
                    }`}
