                                className="px-4 py-2 bg-gray-900 hover:bg-gray-800 border border-gray-800 rounded-lg text-gray-400 hover:text-gray-200 transition-all"
                                title="Refine current shader with new prompt"
                            >
                                <RefreshCw size={16} className={isGenerating ? "animate-spin" : ""} />
                            </button>
                        </div>
                        {error && (
                            <div className="p-3 bg-red-950/30 border border-red-900/30 rounded-lg text-red-400 text-xs flex gap-2 items-start">
                                <AlertCircle size={14} className="mt-0.5 shrink-0" />
                                <span>{error}</span>
                            </div>
                        )}
                    </div>

                    {/* Parameters Section */}
                    <div className="flex-1">
                        <div className="p-4 bg-[#0a0a0a] sticky top-0 border-b border-gray-800 z-10 flex justify-between items-center backdrop-blur-sm bg-opacity-90">
                            <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Parameters</span>
                        </div>
                        <Controls 
                            metadata={parsedShader.metadata} 
                            values={uniforms} 
                            sources={inputSources}
                            textureSettings={textureSettings}
                            onChange={handleUniformChange} 
                            onSourceChange={handleSourceChange}
                            onTextureSettingChange={handleTextureSettingChange}
                            onImageUpload={handleImageUpload}
                        />

                        {/* Live Data Visualizer */}
                        {(isMicActive || isWebcamActive) && (
                            <div className="p-4 border-t border-gray-800 space-y-3">
                                 <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block">Signal Analysis</span>

                                 {isMicActive && (
                                     <div className="space-y-2">
                                         <div className="flex justify-between text-xs text-gray-500">
                                             <span>FFT Spectrum</span>
                                             <span className="text-cyan-500 font-mono">{(audioVolume * 100).toFixed(0)}%</span>
                                         </div>
                                         <div className="h-12 bg-gray-900 rounded border border-gray-800 overflow-hidden relative">
                                             <canvas ref={fftCanvasRef} width={256} height={64} className="w-full h-full opacity-80" />
                                         </div>
                                     </div>
                                 )}

                                 <div className="grid grid-cols-2 gap-2 text-xs text-gray-500 pt-1 font-mono">
                                    <div className="bg-gray-900 rounded p-2 border border-gray-800">
                                        <span className="block text-[10px] text-gray-600 mb-1">TILT X</span>
                                        {tilt.x.toFixed(2)}
                                    </div>
