                        </div>
                        <pre className="whitespace-pre-wrap text-[10px] opacity-80">{compileError}</pre>
                    </div>
                )}

                <div className="w-full h-full flex items-center justify-center overflow-hidden bg-black shadow-inner">
                    <ShaderCanvas 
                        parsedShader={parsedShader} 
                        uniforms={uniforms} 
                        sources={inputSources}
                        textureSettings={textureSettings}
                        videoElement={videoElement}
                        audioVolume={audioVolume}
                        audioDataArray={audioDataArray}
                        mouse={mousePos}
                        tilt={tilt}
                        onCompileError={setCompileError}
                        onCanvasRef={(ref) => canvasRef.current = ref}
                    />
                </div>

                {/* Floating Preview Controls */}
                <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 px-6 py-2 bg-gray-900/80 backdrop-blur-xl rounded-full border border-gray-700/50 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-2 group-hover:translate-y-0 shadow-xl">
                    <button onClick={() => setIsPlaying(!isPlaying)} className="text-white hover:text-cyan-400 transition-colors">
                        {isPlaying ? <Pause size={18} /> : <Play size={18} />}
                    </button>
                    <div className="w-px h-4 bg-gray-700"></div>
                    <span className="text-[10px] text-gray-400 font-mono tracking-wider">
                         {canvasRef.current ? `${canvasRef.current.width} x ${canvasRef.current.height}` : 'INITIALIZING'}
                    </span>
                </div>
            </div>

            {/* Code Editor Area */}
            {showCode && (
                <div className="h-1/2 border-t border-gray-800 bg-[#080808] flex flex-col">
                    <div className="flex items-center justify-between px-4 py-2 border-b border-gray-800 bg-[#0a0a0a]">
                        <span className="text-[10px] text-gray-500 font-mono uppercase tracking-wider">shader.fs</span>
                        <button 
                            onClick={copyToClipboard}
                            className="text-gray-400 hover:text-white transition-colors p-1"
                            title="Copy Code"
                        >
                            {copied ? <Check size={14} className="text-green-500" /> : <Copy size={14} />}
                        </button>
                    </div>
                    <div className="flex-1 overflow-auto p-4 relative">
                        <textarea 
                            value={code}
                            onChange={(e) => updateCode(e.target.value)}
                            spellCheck={false}
                            className="w-full h-full bg-transparent text-gray-300 font-mono text-xs leading-5 resize-none outline-none"
                        />
                    </div>
                </div>
            )}

        </div>
      </div>
    </div>
  );
};

