import { GoogleGenAI } from "@google/genai";
import { cleanISFCode } from "../utils/isf";

// Standard ISF prompt prefix to ensure consistent output
const SYSTEM_INSTRUCTION = `
You are an expert Graphics Engineer specializing in GLSL and the Interactive Shader Format (ISF). 
Your goal is to generate high-quality, creative, and efficient ISF shaders for use in VDMX6.

Rules:
1. Output COMPLETE, VALID ISF code.
2. The code MUST start with a valid JSON configuration block inside a multi-line comment /* ... */.
3. Define INPUTS in the JSON for customizable parameters (e.g., speed, color, scale).
4. Do NOT manually declare 'uniform float ...' for variables defined in INPUTS. The ISF host does this automatically.
5. Use standard ISF uniforms: TIME, RENDERSIZE.
6. Use gl_FragColor for output.
7. Do NOT use #version directives (ISF implies this).
8. Do NOT include markdown code fences (like \`\`\`glsl) in your final output if possible.
9. PREFER PROCEDURAL GENERATION. Use Raymarching, SDFs, FBM noise, and cellular automata.

Audio Reactivity Rules:
1. If "Audio Reactive" is requested, prefer using 'uniform sampler2D AUDIO_SPECTRUM'.
2. AUDIO_SPECTRUM is a 128x1 texture.
3. Access frequency data like this: 'float low = texture2D(AUDIO_SPECTRUM, vec2(0.1, 0.0)).r;' (Bass).
4. Access high frequencies like: 'float high = texture2D(AUDIO_SPECTRUM, vec2(0.9, 0.0)).r;' (Treble).
5. Alternatively, use 'uniform float AUDIO_VOL' for simple volume reactivity.

Inputs:
1. 'vec2 MOUSE' (0.0 to 1.0)
2. 'vec2 TILT' (-1.0 to 1.0)
3. 'sampler2D AUDIO_SPECTRUM' (FFT data)
4. 'float AUDIO_VOL' (0.0 to 1.0)
5. If using image inputs, use standard ISF macros (IMG_NORM_PIXEL, IMG_THIS_PIXEL).

Generate SINGLE PASS shaders only.
`;

const REPAIR_INSTRUCTION = `
You are a GLSL Compiler and ISF Validator.
Your task is to FIX broken ISF shader code.
1. Analyze the provided code and the error message (if any).
2. Fix syntax errors (missing semicolons, mismatched braces, type mismatches).
3. Ensure the JSON blob at the top is valid JSON.
4. Ensure variables in the JSON INPUTS are NOT redeclared as uniforms in the GLSL body (this causes redefinition errors).
5. Ensure main() function exists and sets gl_FragColor.
6. RETURN ONLY THE FIXED CODE. Do not add explanations.
`;

export const generateShader = async (prompt: string, currentCode?: string): Promise<string> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let finalPrompt = prompt;
  if (currentCode) {
    finalPrompt = `Refine this existing ISF shader based on the request: "${prompt}".\n\nExisting Code:\n${currentCode}`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: finalPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        // Enable thinking for complex shader math/logic
        thinkingConfig: { thinkingBudget: 2048 }, 
        maxOutputTokens: 8192,
      },
    });

    let text = response.text || "";

    // Cleanup markdown if present
    text = text.replace(/^```glsl\s*/i, '').replace(/^```\s*/, '').replace(/```$/, '').trim();

    // Apply additional ISF specific cleaning
    text = cleanISFCode(text);

    return text;
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

export const repairShader = async (code: string, errorHint?: string): Promise<string> => {
    if (!process.env.API_KEY) throw new Error("API Key is missing");

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
    Fix this ISF Shader.

    ${errorHint ? `COMPILER ERROR: ${errorHint}` : 'Check for syntax and logic errors.'}

    BROKEN CODE:
    ${code}
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: REPAIR_INSTRUCTION,
                thinkingConfig: { thinkingBudget: 1024 }, // Lower budget for repairs, needs logic not creativity
            }
        });

        let text = response.text || "";
        text = text.replace(/^```glsl\s*/i, '').replace(/^```\s*/, '').replace(/```$/, '').trim();
        text = cleanISFCode(text);
        return text;

    } catch (error) {
        console.error("Gemini Repair Error", error);
        throw error;
    }
}

import React, { useState, useEffect, useRef } from 'react';
import { 
