  Download, 
  Code, 
  Maximize2, 
  AlertCircle, 
  Play, 
  Pause,
  RefreshCw,
  Copy,
  Check,
  Mic,
  MicOff,
  Video,
  VideoOff,
  Disc,
  Undo2,
  Redo2,
  BookTemplate,
  Star,
  Clock,
  Trash2,
  Library,
  Sliders,
  Upload,
  Wrench,
  FileCode
} from 'lucide-react';
import { generateShader, repairShader } from './services/gemini';
import { parseISF } from './utils/isf';
import { DEFAULT_SHADER } from './constants';
import ShaderCanvas from './components/ShaderCanvas';
import Controls from './components/Controls';
import { ParsedShader, UniformValues, ISFInput, TextureSettings, TextureFilter } from './types';
import { useMedia } from './hooks/useMedia';

const PRESETS = [
    { label: "Empty", prompt: "" },
    { label: "Neon Tunnel", prompt: "A psychedelic infinite neon tunnel with glitch effects and chromatic aberration. High contrast." },
    { label: "Liquid Metal", prompt: "Reflective liquid metal surface with ripple effects reacting to mouse position. Raymarched." },
    { label: "Audio Reactor", prompt: "A circular audio visualizer that reacts to the AUDIO_SPECTRUM. Bass pulses in the center, treble on the outside." },
    { label: "Cyberpunk City", prompt: "Procedural cityscape from above, moving forward, neon lights, rain on lens, retro aesthetic." },
    { label: "Fractal Dream", prompt: "Mandelbulb or julia set fractal zooming in and out with color shifting palette." }
];

interface ShaderLogEntry {
    id: string;
    timestamp: number;
    prompt: string;
    code: string;
}

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('A psychedelic tunnel with neon colors and glitch effects');
  const [code, setCode] = useState<string>(DEFAULT_SHADER);

  // Undo/Redo History
  const [history, setHistory] = useState<string[]>([DEFAULT_SHADER]);
  const [historyIndex, setHistoryIndex] = useState(0);

  // Library State
  const [generations, setGenerations] = useState<ShaderLogEntry[]>([]);
  const [favorites, setFavorites] = useState<ShaderLogEntry[]>([]);
  const [activeTab, setActiveTab] = useState<'create' | 'library'>('create');

  const [parsedShader, setParsedShader] = useState<ParsedShader>(parseISF(DEFAULT_SHADER));
  const [uniforms, setUniforms] = useState<UniformValues>({});

  // Media & Texture State
  const [inputSources, setInputSources] = useState<Record<string, string>>({});
  const [textureSettings, setTextureSettings] = useState<TextureSettings>({});

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showCode, setShowCode] = useState(false);
  const [isPlaying, setIsPlaying] = useState(true);
  const [compileError, setCompileError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [showPresets, setShowPresets] = useState(false);

  // Sensor Data State
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });
  const [tilt, setTilt] = useState({ x: 0, y: 0 });

  // Hooks
  const { 
    isWebcamActive, toggleWebcam, videoElement,
    isMicActive, toggleMic, audioVolume, audioDataArray,
    isRecording, startRecording, stopRecording
  } = useMedia();

  const fftCanvasRef = useRef<HTMLCanvasElement>(null);

  // --- Load/Save LocalStorage ---
  useEffect(() => {
      try {
          const savedFavs = localStorage.getItem('aether_favorites');
          const savedGens = localStorage.getItem('aether_generations');
          if (savedFavs) setFavorites(JSON.parse(savedFavs));
          if (savedGens) setGenerations(JSON.parse(savedGens));
      } catch (e) {
          console.error("Failed to load local storage", e);
      }
  }, []);

  useEffect(() => {
      localStorage.setItem('aether_favorites', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
      localStorage.setItem('aether_generations', JSON.stringify(generations));
  }, [generations]);

  // --- Interaction Handlers ---

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = 1.0 - (e.clientY - rect.top) / rect.height; 
    setMousePos({ x: Math.max(0, Math.min(1, x)), y: Math.max(0, Math.min(1, y)) });
  };

  useEffect(() => {
    const handleOrientation = (e: DeviceOrientationEvent) => {
       const x = (e.gamma || 0) / 90; 
       const y = (e.beta || 0) / 90;
       setTilt({ x, y });
    };
    window.addEventListener('deviceorientation', handleOrientation);
    return () => window.removeEventListener('deviceorientation', handleOrientation);
  }, []);

  const updateCode = (newCode: string, addToHistory = true) => {
      setCode(newCode);
      if (addToHistory) {
          const newHistory = history.slice(0, historyIndex + 1);
          newHistory.push(newCode);
          setHistory(newHistory);
          setHistoryIndex(newHistory.length - 1);
      }
  };

  const handleUndo = () => {
      if (historyIndex > 0) {
          const newIndex = historyIndex - 1;
          setHistoryIndex(newIndex);
          setCode(history[newIndex]);
      }
  };

  const handleRedo = () => {
      if (historyIndex < history.length - 1) {
          const newIndex = historyIndex + 1;
          setHistoryIndex(newIndex);
          setCode(history[newIndex]);
      }
  };

  // Parse code whenever it changes
  useEffect(() => {
    const parsed = parseISF(code);
    setParsedShader(parsed);

    // Initialize defaults
    if (parsed.metadata && parsed.metadata.INPUTS) {
      const initialUniforms: UniformValues = {};
      const initialSources: Record<string, string> = {};
      const initialTextureSettings: TextureSettings = {};

      parsed.metadata.INPUTS.forEach((input: ISFInput) => {
         initialUniforms[input.NAME] = input.DEFAULT;
         if (input.TYPE === 'image') {
             initialSources[input.NAME] = 'noise'; 
             initialTextureSettings[input.NAME] = { filter: 'LINEAR' };
         }
      });
      setUniforms(prev => ({ ...initialUniforms, ...prev }));
      setInputSources(prev => ({ ...initialSources, ...prev }));
      setTextureSettings(prev => ({ ...initialTextureSettings, ...prev }));
    }
  }, [code]);

  // UI Visualizer for FFT
  useEffect(() => {
      if (!isMicActive || !audioDataArray || !fftCanvasRef.current) return;

      const ctx = fftCanvasRef.current.getContext('2d');
      if (!ctx) return;

      const draw = () => {
          if (!fftCanvasRef.current) return; 
          const w = fftCanvasRef.current.width;
          const h = fftCanvasRef.current.height;
          ctx.clearRect(0, 0, w, h);
          ctx.fillStyle = '#06b6d4'; // Cyan

          const barWidth = w / audioDataArray.length;

          for(let i=0; i<audioDataArray.length; i++) {
              const val = audioDataArray[i] / 255.0;
              const barHeight = val * h;
              ctx.fillRect(i * barWidth, h - barHeight, barWidth - 1, barHeight);
          }
          requestAnimationFrame(draw);
      };
      const id = requestAnimationFrame(draw);
      return () => cancelAnimationFrame(id);
  }, [isMicActive, audioDataArray]);

  const handleGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setError(null);
    try {
      const newCode = await generateShader(prompt);
      updateCode(newCode);

      // Add to Generations History
      const entry: ShaderLogEntry = {
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          prompt: prompt,
          code: newCode
      };
      setGenerations(prev => [entry, ...prev].slice(0, 50)); // Limit to 50
    } catch (err: any) {
      setError(err.message || "Failed to generate shader");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRefine = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setError(null);
    try {
      const newCode = await generateShader(prompt, code);
      updateCode(newCode);

      // Add to Generations History
      const entry: ShaderLogEntry = {
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          prompt: `${prompt} (Refined)`,
          code: newCode
      };
      setGenerations(prev => [entry, ...prev].slice(0, 50));
    } catch (err: any) {
      setError(err.message || "Failed to refine shader");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRepair = async () => {
      setIsGenerating(true);
      setError(null);
      try {
          // Pass the current code AND the current compiler error to the AI
          const errorHint = compileError || undefined;
          const fixedCode = await repairShader(code, errorHint);

          updateCode(fixedCode);
          setCompileError(null); // Optimistically clear error

          // Add to History as a repair
          const entry: ShaderLogEntry = {
            id: crypto.randomUUID(),
            timestamp: Date.now(),
            prompt: "Auto-Repair Shader",
            code: fixedCode
          };
          setGenerations(prev => [entry, ...prev].slice(0, 50));

      } catch (err: any) {
          setError(err.message || "Failed to repair shader");
      } finally {
          setIsGenerating(false);
      }
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (ev) => {
          const text = ev.target?.result;
          if (typeof text === 'string') {
              updateCode(text);
              setPrompt(`Imported: ${file.name}`);
              setShowCode(true); // Show the code editor so they can see what they imported
          }
      };
      reader.readAsText(file);
      // Reset input so same file can be selected again
      e.target.value = '';
  };

  const toggleFavorite = () => {
      const existingIndex = favorites.findIndex(f => f.code === code);
      if (existingIndex >= 0) {
          setFavorites(prev => prev.filter((_, i) => i !== existingIndex));
      } else {
          setFavorites(prev => [{
              id: crypto.randomUUID(),
              timestamp: Date.now(),
              prompt: prompt || "Untitled Shader",
              code: code
          }, ...prev]);
      }
  };

  const isCurrentFavorite = favorites.some(f => f.code === code);

  const loadEntry = (entry: ShaderLogEntry) => {
      setCode(entry.code);
      setPrompt(entry.prompt);
      updateCode(entry.code); 
  };

  const deleteEntry = (e: React.MouseEvent, id: string, list: 'favorites' | 'generations') => {
      e.stopPropagation();
      if (list === 'favorites') {
          setFavorites(prev => prev.filter(x => x.id !== id));
      } else {
          setGenerations(prev => prev.filter(x => x.id !== id));
      }
  };

  const handleUniformChange = (name: string, value: any) => {
    setUniforms(prev => ({ ...prev, [name]: value }));
  };

  const handleSourceChange = (name: string, source: string) => {
      if (source === 'webcam' && !isWebcamActive) {
          toggleWebcam(); 
      }
      setInputSources(prev => ({ ...prev, [name]: source }));
  };

  const handleTextureSettingChange = (name: string, filter: TextureFilter) => {
      setTextureSettings(prev => ({
          ...prev,
          [name]: { ...prev[name], filter }
      }));
  };

  const handleImageUpload = (name: string, file: File) => {
      const url = URL.createObjectURL(file);
      setInputSources(prev => ({ ...prev, [name]: url }));
  }

  const handleDownload = () => {
    const blob = new Blob([code], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Aether_Gen_${Date.now()}.fs`; 
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  const toggleRecording = () => {
      if (isRecording) {
          stopRecording();
      } else if (canvasRef.current) {
          startRecording(canvasRef.current);
      }
  }

  return (
    <div className="flex flex-col h-screen bg-[#050505] text-gray-200 font-sans selection:bg-cyan-500/30">
