      <header className="h-16 border-b border-gray-800 flex items-center justify-between px-6 bg-[#0a0a0a]/90 backdrop-blur-md z-50">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-gradient-to-br from-cyan-600 to-blue-700 rounded-lg flex items-center justify-center shadow-[0_0_15px_rgba(8,145,178,0.3)]">
            <Wand2 size={20} className="text-white" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight text-white leading-none">
                Aether
            </h1>
            <span className="text-[10px] font-medium text-cyan-500 tracking-[0.2em] uppercase">ISF Generator</span>
          </div>
        </div>

        {/* Top Controls */}
        <div className="flex items-center gap-3">
             <div className="flex items-center bg-gray-900/50 rounded-lg p-1 border border-gray-800">
                <button 
                    onClick={toggleMic}
                    title={isMicActive ? "Mute Microphone" : "Enable Microphone Analysis"}
                    className={`p-2 rounded-md transition-all ${isMicActive ? 'bg-red-500/20 text-red-400 shadow-[0_0_10px_rgba(239,68,68,0.2)]' : 'text-gray-400 hover:text-white hover:bg-gray-800'}`}
                >
                    {isMicActive ? <Mic size={18} /> : <MicOff size={18} />}
                </button>
                <button 
                    onClick={toggleWebcam}
                    title={isWebcamActive ? "Turn Off Webcam" : "Enable Webcam"}
                    className={`p-2 rounded-md transition-all ${isWebcamActive ? 'bg-green-500/20 text-green-400 shadow-[0_0_10px_rgba(34,197,94,0.2)]' : 'text-gray-400 hover:text-white hover:bg-gray-800'}`}
                >
                    {isWebcamActive ? <Video size={18} /> : <VideoOff size={18} />}
                </button>
             </div>

             <button 
                onClick={toggleFavorite}
                title="Add to Favorites"
                className={`p-2 rounded-md border transition-all ${isCurrentFavorite 
                    ? 'bg-yellow-500/10 text-yellow-400 border-yellow-500/50 shadow-[0_0_10px_rgba(234,179,8,0.2)]' 
                    : 'bg-gray-900 border-gray-800 text-gray-400 hover:bg-gray-800 hover:text-yellow-200'}`}
             >
                 <Star size={18} fill={isCurrentFavorite ? "currentColor" : "none"} />
             </button>

             <button 
                onClick={toggleRecording}
                title={isRecording ? "Stop Recording" : "Start Recording"}
                className={`flex items-center gap-2 px-3 py-2 rounded-md transition-all ${
                    isRecording 
                    ? 'bg-red-600 text-white animate-pulse shadow-[0_0_15px_rgba(220,38,38,0.5)]' 
                    : 'bg-gray-900 border border-gray-700 text-gray-300 hover:bg-gray-800'
