                    {/* Prompt Section */}
                    <div className="p-4 border-b border-gray-800 space-y-3">
                        <div className="flex justify-between items-center">
                            <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Generative Prompt</label>

                            {/* Presets Dropdown */}
                            <div className="relative">
                                <button 
                                    onClick={() => setShowPresets(!showPresets)}
                                    className="text-xs flex items-center gap-1 text-cyan-500 hover:text-cyan-400 transition-colors"
                                >
                                    <BookTemplate size={12} />
                                    Presets
                                </button>
                                {showPresets && (
                                    <div className="absolute right-0 top-6 w-48 bg-gray-900 border border-gray-700 rounded-lg shadow-xl z-20 py-1">
                                        {PRESETS.map((p) => (
                                            <button
                                                key={p.label}
                                                className="w-full text-left px-3 py-2 text-xs text-gray-300 hover:bg-gray-800 hover:text-white transition-colors"
                                                onClick={() => {
                                                    setPrompt(p.prompt);
                                                    setShowPresets(false);
                                                }}
                                            >
                                                {p.label}
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="relative">
                            <textarea 
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                                className="w-full bg-[#050505] border border-gray-800 rounded-lg p-3 text-sm focus:ring-1 focus:ring-cyan-500 focus:border-cyan-500 outline-none resize-none h-28 placeholder-gray-700 transition-all font-light"
                                placeholder="Describe your vision..."
                            />

                            {/* History Controls inside prompt area */}
                            <div className="absolute bottom-3 right-3 flex gap-1">
                                <button 
                                    onClick={handleUndo} 
                                    disabled={historyIndex <= 0}
                                    className="p-1.5 rounded bg-gray-800 hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
                                    title="Undo"
                                >
                                    <Undo2 size={12} className="text-gray-300" />
                                </button>
                                <button 
                                    onClick={handleRedo} 
                                    disabled={historyIndex >= history.length - 1}
                                    className="p-1.5 rounded bg-gray-800 hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
                                    title="Redo"
                                >
                                    <Redo2 size={12} className="text-gray-300" />
                                </button>
                            </div>
                        </div>

                        <div className="flex gap-2">
                            <button 
                                onClick={handleGenerate}
                                disabled={isGenerating}
                                className={`flex-1 py-2.5 rounded-lg text-sm font-semibold flex items-center justify-center gap-2 transition-all ${
                                    isGenerating 
                                    ? 'bg-gray-800 cursor-not-allowed text-gray-500' 
                                    : 'bg-gradient-to-r from-cyan-600 to-blue-600 hover:from-cyan-500 hover:to-blue-500 text-white shadow-lg shadow-cyan-900/30'
                                }`}
                            >
                                {isGenerating ? (
                                    <RefreshCw className="animate-spin" size={16} />
                                ) : (
                                    <Wand2 size={16} />
                                )}
                                {isGenerating ? 'Synthesizing...' : 'Generate Shader'}
                            </button>
                             <button 
                                onClick={handleRefine}
                                disabled={isGenerating}
                                className="px-4 py-2 bg-gray-900 hover:bg-gray-800 border border-gray-800 rounded-lg text-gray-400 hover:text-gray-200 transition-all"
                                title="Refine current shader with new prompt"
                            >
                                <RefreshCw size={16} className={isGenerating ? "animate-spin" : ""} />
                            </button>
                        </div>

                        {/* Repair / Error Section */}
                        <div className="flex gap-2 mt-2">
                            <button 
                                onClick={handleRepair}
                                disabled={isGenerating}
                                className={`flex-1 py-2 rounded-lg text-xs font-semibold flex items-center justify-center gap-2 transition-all border ${
                                    compileError 
                                    ? 'bg-red-900/20 border-red-800/50 text-red-400 hover:bg-red-900/40 hover:text-red-300' 
                                    : 'bg-gray-900 border-gray-800 text-gray-500 hover:bg-gray-800 hover:text-gray-300'
                                }`}
                                title="Fix syntax errors and recompile"
                            >
                                <Wrench size={14} className={isGenerating ? "animate-spin" : ""} />
                                {compileError ? "Fix Compilation Errors" : "Auto-Repair Code"}
                            </button>
                        </div>

                        {error && (
                            <div className="p-3 bg-red-950/30 border border-red-900/30 rounded-lg text-red-400 text-xs flex gap-2 items-start">
                                <AlertCircle size={14} className="mt-0.5 shrink-0" />
                                <span>{error}</span>
                            </div>
                        )}
                    </div>

                    {/* Parameters Section */}
                    <div className="flex-1">
                        <div className="p-4 bg-[#0a0a0a] sticky top-0 border-b border-gray-800 z-10 flex justify-between items-center backdrop-blur-sm bg-opacity-90">
                            <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Parameters</span>
                        </div>
                        <Controls 
                            metadata={parsedShader.metadata} 
                            values={uniforms} 
                            sources={inputSources}
                            textureSettings={textureSettings}
                            onChange={handleUniformChange} 
                            onSourceChange={handleSourceChange}
                            onTextureSettingChange={handleTextureSettingChange}
                            onImageUpload={handleImageUpload}
                        />

                        {/* Live Data Visualizer */}
                        {(isMicActive || isWebcamActive) && (
                            <div className="p-4 border-t border-gray-800 space-y-3">
                                 <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block">Signal Analysis</span>

                                 {isMicActive && (
                                     <div className="space-y-2">
                                         <div className="flex justify-between text-xs text-gray-500">
                                             <span>FFT Spectrum</span>
                                             <span className="text-cyan-500 font-mono">{(audioVolume * 100).toFixed(0)}%</span>
                                         </div>
                                         <div className="h-12 bg-gray-900 rounded border border-gray-800 overflow-hidden relative">
                                             <canvas ref={fftCanvasRef} width={256} height={64} className="w-full h-full opacity-80" />
                                         </div>
                                     </div>
                                 )}

                                 <div className="grid grid-cols-2 gap-2 text-xs text-gray-500 pt-1 font-mono">
                                    <div className="bg-gray-900 rounded p-2 border border-gray-800">
                                        <span className="block text-[10px] text-gray-600 mb-1">TILT X</span>
                                        {tilt.x.toFixed(2)}
                                    </div>
                                    <div className="bg-gray-900 rounded p-2 border border-gray-800">
                                        <span className="block text-[10px] text-gray-600 mb-1">TILT Y</span>
                                        {tilt.y.toFixed(2)}
                                    </div>
                                 </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* LIBRARY TAB */}
            {activeTab === 'library' && (
                <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-6">
                    {/* Favorites Section */}
                    <div>
                        <div className="flex items-center gap-2 mb-3 text-yellow-500">
                            <Star size={14} fill="currentColor" />
                            <span className="text-xs font-bold uppercase tracking-wider">Favorites</span>
                        </div>
                        {favorites.length === 0 ? (
                            <div className="text-xs text-gray-600 italic">No favorites yet. Click the star to save one.</div>
                        ) : (
                            <div className="space-y-2">
                                {favorites.map(fav => (
                                    <div 
                                        key={fav.id} 
                                        onClick={() => loadEntry(fav)}
                                        className="group p-3 bg-gray-900/50 border border-gray-800 rounded-lg hover:border-yellow-500/50 hover:bg-gray-900 cursor-pointer transition-all relative"
                                    >
                                        <div className="pr-6">
                                            <p className="text-xs text-gray-300 font-medium line-clamp-2">{fav.prompt}</p>
                                            <p className="text-[10px] text-gray-600 mt-1 font-mono">{new Date(fav.timestamp).toLocaleDateString()}</p>
                                        </div>
                                        <button 
                                            onClick={(e) => deleteEntry(e, fav.id, 'favorites')}
                                            className="absolute top-2 right-2 p-1 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            <Trash2 size={12} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* History Section */}
                    <div>
                         <div className="flex items-center gap-2 mb-3 text-cyan-500">
                            <Clock size={14} />
                            <span className="text-xs font-bold uppercase tracking-wider">Recent Creations</span>
                        </div>
                        {generations.length === 0 ? (
                            <div className="text-xs text-gray-600 italic">No history yet. Generate something!</div>
                        ) : (
                            <div className="space-y-2">
                                {generations.map(gen => (
                                    <div 
                                        key={gen.id} 
                                        onClick={() => loadEntry(gen)}
                                        className="group p-3 bg-gray-900/30 border border-gray-800 rounded-lg hover:border-cyan-500/30 hover:bg-gray-900 cursor-pointer transition-all relative"
                                    >
                                        <div className="pr-6">
                                            <p className="text-xs text-gray-400 line-clamp-2">{gen.prompt}</p>
                                            <p className="text-[10px] text-gray-600 mt-1 font-mono">{new Date(gen.timestamp).toLocaleTimeString()}</p>
                                        </div>
                                         <button 
                                            onClick={(e) => deleteEntry(e, gen.id, 'generations')}
                                            className="absolute top-2 right-2 p-1 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            <Trash2 size={12} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>

        {/* Right Content - Preview & Editor */}
        <div className="flex-1 flex flex-col relative bg-[#050505]">

            {/* Viewport Area */}
            <div 
                className={`relative flex-1 ${showCode ? 'h-1/2' : 'h-full'} transition-all duration-300 group`}
                onMouseMove={handleMouseMove}
            >
                <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-20 pointer-events-none"></div>

                {compileError && (
                    <div className="absolute top-4 left-4 right-4 z-20 bg-red-950/90 backdrop-blur-md border border-red-500/30 text-red-200 p-4 rounded-lg text-sm font-mono overflow-auto max-h-40 shadow-2xl">
                        <div className="flex items-center gap-2 mb-2 font-bold text-red-100">
                            <AlertCircle size={16} />
                            Compilation Error
                        </div>
                        <pre className="whitespace-pre-wrap text-[10px] opacity-80">{compileError}</pre>
                    </div>
                )}

                <div className="w-full h-full flex items-center justify-center overflow-hidden bg-black shadow-inner">
                    <ShaderCanvas 
                        parsedShader={parsedShader} 
                        uniforms={uniforms} 
                        sources={inputSources}
                        textureSettings={textureSettings}
                        videoElement={videoElement}
                        audioVolume={audioVolume}
                        audioDataArray={audioDataArray}
                        mouse={mousePos}
                        tilt={tilt}
                        onCompileError={setCompileError}
                        onCanvasRef={(ref) => canvasRef.current = ref}
                    />
                </div>

                {/* Floating Preview Controls */}
                <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 px-6 py-2 bg-gray-900/80 backdrop-blur-xl rounded-full border border-gray-700/50 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-2 group-hover:translate-y-0 shadow-xl">
                    <button onClick={() => setIsPlaying(!isPlaying)} className="text-white hover:text-cyan-400 transition-colors">
                        {isPlaying ? <Pause size={18} /> : <Play size={18} />}
                    </button>
                    <div className="w-px h-4 bg-gray-700"></div>
                    <span className="text-[10px] text-gray-400 font-mono tracking-wider">
                         {canvasRef.current ? `${canvasRef.current.width} x ${canvasRef.current.height}` : 'INITIALIZING'}
                    </span>
                    <div className="w-px h-4 bg-gray-700"></div>
                    <button onClick={() => setShowCode(!showCode)} className={`transition-colors ${showCode ? 'text-cyan-400' : 'text-white hover:text-cyan-400'}`}>
                        <FileCode size={18} />
                    </button>
                </div>
            </div>

            {/* Code Editor Area */}
            {showCode && (
                <div className="h-1/2 border-t border-gray-800 bg-[#080808] flex flex-col">
                    <div className="flex items-center justify-between px-4 py-2 border-b border-gray-800 bg-[#0a0a0a]">
                        <span className="text-[10px] text-gray-500 font-mono uppercase tracking-wider">shader.fs</span>
                        <div className="flex items-center gap-2">
                            {compileError && (
                                <button 
                                    onClick={handleRepair}
                                    className="text-xs flex items-center gap-1 text-red-400 hover:text-red-300 mr-2 bg-red-900/20 px-2 py-1 rounded border border-red-900/50"
                                >
                                    <Wrench size={12} className={isGenerating ? "animate-spin" : ""} />
                                    <span>AI Fix</span>
                                </button>
                            )}
                            <button 
                                onClick={copyToClipboard}
                                className="text-gray-400 hover:text-white transition-colors p-1"
                                title="Copy Code"
                            >
                                {copied ? <Check size={14} className="text-green-500" /> : <Copy size={14} />}
                            </button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-auto p-4 relative">
                        <textarea 
                            value={code}
                            onChange={(e) => updateCode(e.target.value)}
                            spellCheck={false}
                            className="w-full h-full bg-transparent text-gray-300 font-mono text-xs leading-5 resize-none outline-none"
                        />
                    </div>
                </div>
            )}

        </div>
      </div>
    </div>
  );
};

export default App;

export enum ISFInputType {
  FLOAT = 'float',
  LONG = 'long', // integer in ISF usually maps to long or int logic
  BOOL = 'bool',
  POINT2D = 'point2D',
  COLOR = 'color',
  IMAGE = 'image', // Not fully supported in this web preview, but parsed
}

export interface ISFInput {
  NAME: string;
  TYPE: string;
  LABEL?: string;
  DEFAULT?: any;
  MIN?: number;
  MAX?: number;
  VALUES?: any[]; // For select dropdowns (long)
  LABELS?: string[];
}

export interface ISFMetadata {
  DESCRIPTION?: string;
  CREDIT?: string;
  ISFVSN?: string;
  INPUTS: ISFInput[];
}

export interface ParsedShader {
  rawCode: string;
  metadata: ISFMetadata | null;
  fragmentBody: string;
  error?: string;
}

export interface UniformValues {
  [key: string]: number | boolean | number[] | string;
}

export type TextureFilter = 'LINEAR' | 'NEAREST';
export type TextureWrap = 'REPEAT' | 'CLAMP_TO_EDGE';

export interface TextureSettings {
    [key: string]: {
        filter: TextureFilter;
        wrap: TextureWrap;
    };
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Wand2, 
  Download, 
  Code, 
  Maximize2, 
  AlertCircle, 
  Play, 
  Pause,
  RefreshCw,
  Copy,
  Check,
  Mic,
  MicOff,
  Video,
  VideoOff,
  Disc,
  Undo2,
  Redo2,
  BookTemplate,
  Star,
  Clock,
  Trash2,
  Library,
  Sliders,
  Upload,
  Wrench,
  FileCode
} from 'lucide-react';
import { generateShader, repairShader } from './services/gemini';
import { parseISF } from './utils/isf';
import { DEFAULT_SHADER } from './constants';
import ShaderCanvas from './components/ShaderCanvas';
import Controls from './components/Controls';
import { ParsedShader, UniformValues, ISFInput, TextureSettings, TextureFilter, TextureWrap } from './types';
import { useMedia } from './hooks/useMedia';

const PRESETS = [
    { label: "Empty", prompt: "" },
    { label: "Neon Tunnel", prompt: "A psychedelic infinite neon tunnel with glitch effects and chromatic aberration. High contrast." },
    { label: "Liquid Metal", prompt: "Reflective liquid metal surface with ripple effects reacting to mouse position. Raymarched." },
    { label: "Audio Reactor", prompt: "A circular audio visualizer that reacts to the AUDIO_SPECTRUM. Bass pulses in the center, treble on the outside." },
    { label: "Cyberpunk City", prompt: "Procedural cityscape from above, moving forward, neon lights, rain on lens, retro aesthetic." },
    { label: "Fractal Dream", prompt: "Mandelbulb or julia set fractal zooming in and out with color shifting palette." }
];

interface ShaderLogEntry {
    id: string;
    timestamp: number;
    prompt: string;
    code: string;
}

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('A psychedelic tunnel with neon colors and glitch effects');
  const [code, setCode] = useState<string>(DEFAULT_SHADER);

  // Undo/Redo History
  const [history, setHistory] = useState<string[]>([DEFAULT_SHADER]);
  const [historyIndex, setHistoryIndex] = useState(0);

  // Library State
  const [generations, setGenerations] = useState<ShaderLogEntry[]>([]);
  const [favorites, setFavorites] = useState<ShaderLogEntry[]>([]);
  const [activeTab, setActiveTab] = useState<'create' | 'library'>('create');

  const [parsedShader, setParsedShader] = useState<ParsedShader>(parseISF(DEFAULT_SHADER));
  const [uniforms, setUniforms] = useState<UniformValues>({});

  // Media & Texture State
  const [inputSources, setInputSources] = useState<Record<string, string>>({});
  const [textureSettings, setTextureSettings] = useState<TextureSettings>({});

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showCode, setShowCode] = useState(false);
  const [isPlaying, setIsPlaying] = useState(true);
  const [compileError, setCompileError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [showPresets, setShowPresets] = useState(false);

  // Sensor Data State
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });
  const [tilt, setTilt] = useState({ x: 0, y: 0 });

  // Hooks
  const { 
    isWebcamActive, toggleWebcam, videoElement,
    isMicActive, toggleMic, audioVolume, audioDataArray,
    isRecording, startRecording, stopRecording
  } = useMedia();

  const fftCanvasRef = useRef<HTMLCanvasElement>(null);

  // --- Load/Save LocalStorage ---
  useEffect(() => {
      try {
          const savedFavs = localStorage.getItem('aether_favorites');
          const savedGens = localStorage.getItem('aether_generations');
          if (savedFavs) setFavorites(JSON.parse(savedFavs));
          if (savedGens) setGenerations(JSON.parse(savedGens));
      } catch (e) {
          console.error("Failed to load local storage", e);
      }
  }, []);

  useEffect(() => {
      localStorage.setItem('aether_favorites', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
      localStorage.setItem('aether_generations', JSON.stringify(generations));
  }, [generations]);

  // --- Interaction Handlers ---

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = 1.0 - (e.clientY - rect.top) / rect.height; 
    setMousePos({ x: Math.max(0, Math.min(1, x)), y: Math.max(0, Math.min(1, y)) });
  };

  useEffect(() => {
    const handleOrientation = (e: DeviceOrientationEvent) => {
       const x = (e.gamma || 0) / 90; 
       const y = (e.beta || 0) / 90;
       setTilt({ x, y });
    };
    window.addEventListener('deviceorientation', handleOrientation);
    return () => window.removeEventListener('deviceorientation', handleOrientation);
  }, []);

  const updateCode = (newCode: string, addToHistory = true) => {
      setCode(newCode);
      if (addToHistory) {
          const newHistory = history.slice(0, historyIndex + 1);
          newHistory.push(newCode);
          setHistory(newHistory);
          setHistoryIndex(newHistory.length - 1);
      }
  };

  const handleUndo = () => {
      if (historyIndex > 0) {
          const newIndex = historyIndex - 1;
          setHistoryIndex(newIndex);
          setCode(history[newIndex]);
      }
  };

  const handleRedo = () => {
      if (historyIndex < history.length - 1) {
          const newIndex = historyIndex + 1;
          setHistoryIndex(newIndex);
          setCode(history[newIndex]);
      }
  };

  // Parse code whenever it changes
  useEffect(() => {
    const parsed = parseISF(code);
    setParsedShader(parsed);

    // Initialize defaults
    if (parsed.metadata && parsed.metadata.INPUTS) {
      const initialUniforms: UniformValues = {};
      const initialSources: Record<string, string> = {};
      const initialTextureSettings: TextureSettings = {};

      parsed.metadata.INPUTS.forEach((input: ISFInput) => {
         initialUniforms[input.NAME] = input.DEFAULT;
         if (input.TYPE === 'image') {
             initialSources[input.NAME] = 'noise'; 
             initialTextureSettings[input.NAME] = { filter: 'LINEAR', wrap: 'REPEAT' };
         }
      });
      setUniforms(prev => ({ ...initialUniforms, ...prev }));
      setInputSources(prev => ({ ...initialSources, ...prev }));
      setTextureSettings(prev => ({ ...initialTextureSettings, ...prev }));
    }
  }, [code]);

  // UI Visualizer for FFT
  useEffect(() => {
      if (!isMicActive || !audioDataArray || !fftCanvasRef.current) return;

      const ctx = fftCanvasRef.current.getContext('2d');
      if (!ctx) return;

      const draw = () => {
          if (!fftCanvasRef.current) return; 
          const w = fftCanvasRef.current.width;
          const h = fftCanvasRef.current.height;
          ctx.clearRect(0, 0, w, h);
          ctx.fillStyle = '#06b6d4'; // Cyan

          const barWidth = w / audioDataArray.length;

          for(let i=0; i<audioDataArray.length; i++) {
              const val = audioDataArray[i] / 255.0;
              const barHeight = val * h;
              ctx.fillRect(i * barWidth, h - barHeight, barWidth - 1, barHeight);
          }
          requestAnimationFrame(draw);
      };
      const id = requestAnimationFrame(draw);
      return () => cancelAnimationFrame(id);
  }, [isMicActive, audioDataArray]);

  const handleGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setError(null);
    try {
      const newCode = await generateShader(prompt);
      updateCode(newCode);

      // Add to Generations History
      const entry: ShaderLogEntry = {
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          prompt: prompt,
          code: newCode
      };
      setGenerations(prev => [entry, ...prev].slice(0, 50)); // Limit to 50
    } catch (err: any) {
      setError(err.message || "Failed to generate shader");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRefine = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setError(null);
    try {
      const newCode = await generateShader(prompt, code);
      updateCode(newCode);

      // Add to Generations History
      const entry: ShaderLogEntry = {
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          prompt: `${prompt} (Refined)`,
          code: newCode
      };
      setGenerations(prev => [entry, ...prev].slice(0, 50));
    } catch (err: any) {
      setError(err.message || "Failed to refine shader");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRepair = async () => {
      setIsGenerating(true);
      setError(null);
      try {
          // Pass the current code AND the current compiler error to the AI
          const errorHint = compileError || undefined;
          const fixedCode = await repairShader(code, errorHint);

          updateCode(fixedCode);
          setCompileError(null); // Optimistically clear error

          // Add to History as a repair
          const entry: ShaderLogEntry = {
            id: crypto.randomUUID(),
            timestamp: Date.now(),
            prompt: "Auto-Repair Shader",
            code: fixedCode
          };
          setGenerations(prev => [entry, ...prev].slice(0, 50));

      } catch (err: any) {
          setError(err.message || "Failed to repair shader");
      } finally {
          setIsGenerating(false);
      }
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (ev) => {
          const text = ev.target?.result;
          if (typeof text === 'string') {
              updateCode(text);
              setPrompt(`Imported: ${file.name}`);
              setShowCode(true); // Show the code editor so they can see what they imported
          }
      };
      reader.readAsText(file);
      // Reset input so same file can be selected again
      e.target.value = '';
  };

  const toggleFavorite = () => {
      const existingIndex = favorites.findIndex(f => f.code === code);
      if (existingIndex >= 0) {
          setFavorites(prev => prev.filter((_, i) => i !== existingIndex));
      } else {
          setFavorites(prev => [{
              id: crypto.randomUUID(),
              timestamp: Date.now(),
              prompt: prompt || "Untitled Shader",
              code: code
          }, ...prev]);
      }
  };

  const isCurrentFavorite = favorites.some(f => f.code === code);

  const loadEntry = (entry: ShaderLogEntry) => {
      setCode(entry.code);
      setPrompt(entry.prompt);
      updateCode(entry.code); 
  };

  const deleteEntry = (e: React.MouseEvent, id: string, list: 'favorites' | 'generations') => {
      e.stopPropagation();
      if (list === 'favorites') {
          setFavorites(prev => prev.filter(x => x.id !== id));
      } else {
          setGenerations(prev => prev.filter(x => x.id !== id));
      }
  };

  const handleUniformChange = (name: string, value: any) => {
    setUniforms(prev => ({ ...prev, [name]: value }));
  };

  const handleSourceChange = (name: string, source: string) => {
      if (source === 'webcam' && !isWebcamActive) {
          toggleWebcam(); 
      }
      setInputSources(prev => ({ ...prev, [name]: source }));
  };

  const handleTextureSettingChange = (name: string, update: Partial<{filter: TextureFilter, wrap: TextureWrap}>) => {
      setTextureSettings(prev => ({
          ...prev,
          [name]: { ...prev[name], ...update }
      }));
  };

  const handleImageUpload = (name: string, file: File) => {
      const url = URL.createObjectURL(file);
      setInputSources(prev => ({ ...prev, [name]: url }));
  }

  const handleDownload = () => {
    const blob = new Blob([code], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Aether_Gen_${Date.now()}.fs`; 
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  const toggleRecording = () => {
      if (isRecording) {
          stopRecording();
      } else if (canvasRef.current) {
          startRecording(canvasRef.current);
      }
  }

  return (
    <div className="flex flex-col h-screen bg-[#050505] text-gray-200 font-sans selection:bg-cyan-500/30">
      {/* Header */}
      <header className="h-16 border-b border-gray-800 flex items-center justify-between px-6 bg-[#0a0a0a]/90 backdrop-blur-md z-50">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-gradient-to-br from-cyan-600 to-blue-700 rounded-lg flex items-center justify-center shadow-[0_0_15px_rgba(8,145,178,0.3)]">
            <Wand2 size={20} className="text-white" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight text-white leading-none">
                Aether
            </h1>
            <span className="text-[10px] font-medium text-cyan-500 tracking-[0.2em] uppercase">ISF Generator</span>
          </div>
        </div>

        {/* Top Controls */}
        <div className="flex items-center gap-3">
             <div className="flex items-center bg-gray-900/50 rounded-lg p-1 border border-gray-800">
                <button 
                    onClick={toggleMic}
                    title={isMicActive ? "Mute Microphone" : "Enable Microphone Analysis"}
                    className={`p-2 rounded-md transition-all ${isMicActive ? 'bg-red-500/20 text-red-400 shadow-[0_0_10px_rgba(239,68,68,0.2)]' : 'text-gray-400 hover:text-white hover:bg-gray-800'}`}
                >
                    {isMicActive ? <Mic size={18} /> : <MicOff size={18} />}
                </button>
                <button 
                    onClick={toggleWebcam}
                    title={isWebcamActive ? "Turn Off Webcam" : "Enable Webcam"}
                    className={`p-2 rounded-md transition-all ${isWebcamActive ? 'bg-green-500/20 text-green-400 shadow-[0_0_10px_rgba(34,197,94,0.2)]' : 'text-gray-400 hover:text-white hover:bg-gray-800'}`}
                >
                    {isWebcamActive ? <Video size={18} /> : <VideoOff size={18} />}
                </button>
             </div>

             <button 
                onClick={toggleFavorite}
                title="Add to Favorites"
                className={`p-2 rounded-md border transition-all ${isCurrentFavorite 
                    ? 'bg-yellow-500/10 text-yellow-400 border-yellow-500/50 shadow-[0_0_10px_rgba(234,179,8,0.2)]' 
                    : 'bg-gray-900 border-gray-800 text-gray-400 hover:bg-gray-800 hover:text-yellow-200'}`}
             >
                 <Star size={18} fill={isCurrentFavorite ? "currentColor" : "none"} />
             </button>

             <button 
                onClick={toggleRecording}
                title={isRecording ? "Stop Recording" : "Start Recording"}
                className={`flex items-center gap-2 px-3 py-2 rounded-md transition-all ${
                    isRecording 
                    ? 'bg-red-600 text-white animate-pulse shadow-[0_0_15px_rgba(220,38,38,0.5)]' 
                    : 'bg-gray-900 border border-gray-700 text-gray-300 hover:bg-gray-800'
                }`}
             >
                <Disc size={18} />
                <span className="hidden sm:inline font-medium text-sm">{isRecording ? 'REC' : 'Record'}</span>
             </button>

            <div className="w-px h-6 bg-gray-800 self-center mx-1" />

            <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 px-4 py-2 bg-gray-900 hover:bg-gray-800 rounded-md text-sm transition-colors border border-gray-700 hover:border-gray-600"
            >
                <Upload size={16} />
                <span className="hidden sm:inline">Import</span>
            </button>
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".fs,.frag,.txt" 
                onChange={handleImportFile} 
            />

            <button 
                onClick={handleDownload}
                className="flex items-center gap-2 px-4 py-2 bg-gray-900 hover:bg-gray-800 rounded-md text-sm transition-colors border border-gray-700 hover:border-gray-600"
            >
                <Download size={16} />
                <span className="hidden sm:inline">Export</span>
            </button>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex-1 flex overflow-hidden">

        {/* Left Sidebar */}
        <div className="w-full md:w-[360px] lg:w-[420px] flex flex-col border-r border-gray-800 bg-[#0a0a0a] overflow-hidden">

            {/* Sidebar Tabs */}
            <div className="flex border-b border-gray-800">
                <button 
                    onClick={() => setActiveTab('create')}
                    className={`flex-1 py-3 text-[10px] font-bold uppercase tracking-wider flex items-center justify-center gap-2 transition-colors ${
                        activeTab === 'create' 
                        ? 'bg-[#0a0a0a] text-cyan-500 border-b-2 border-cyan-500' 
                        : 'bg-[#050505] text-gray-500 hover:text-gray-300 hover:bg-[#0a0a0a]'
                    }`}
                >
                    <Sliders size={14} />
