                                            <p className="text-[10px] text-gray-600 mt-1 font-mono">{new Date(gen.timestamp).toLocaleTimeString()}</p>
                                        </div>
                                         <button 
                                            onClick={(e) => deleteEntry(e, gen.id, 'generations')}
                                            className="absolute top-2 right-2 p-1 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            <Trash2 size={12} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>

        {/* Right Content - Preview & Editor */}
        <div className="flex-1 flex flex-col relative bg-[#050505]">

            {/* Viewport Area */}
            <div 
                className={`relative flex-1 ${showCode ? 'h-1/2' : 'h-full'} transition-all duration-300 group`}
