                        </div>
                    </div>
                    <div className="flex-1 overflow-auto p-4 relative">
                        <textarea 
                            value={code}
                            onChange={(e) => updateCode(e.target.value)}
                            spellCheck={false}
                            className="w-full h-full bg-transparent text-gray-300 font-mono text-xs leading-5 resize-none outline-none"
                        />
                    </div>
                </div>
            )}

        </div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { ISFInput, ISFMetadata, UniformValues, TextureSettings, TextureFilter, TextureWrap } from '../types';
import { Camera, Image as ImageIcon, Sparkles, Grid3X3, Layers, Repeat, Minimize2 } from 'lucide-react';

interface ControlsProps {
  metadata: ISFMetadata | null;
  values: UniformValues;
  sources: Record<string, string>; // 'noise', 'webcam', or blob URL
  textureSettings: TextureSettings;
  onChange: (name: string, value: any) => void;
  onSourceChange: (name: string, source: string) => void;
  onTextureSettingChange: (name: string, update: Partial<{filter: TextureFilter, wrap: TextureWrap}>) => void;
  onImageUpload: (name: string, file: File) => void;
}

const Controls: React.FC<ControlsProps> = ({ 
    metadata, 
    values, 
    sources, 
    textureSettings,
    onChange, 
    onSourceChange,
    onTextureSettingChange,
    onImageUpload
}) => {
  if (!metadata || !metadata.INPUTS || metadata.INPUTS.length === 0) {
    return <div className="text-gray-500 text-sm italic p-4">No interactive parameters found.</div>;
  }

  return (
    <div className="space-y-4 p-4">
      {metadata.INPUTS.map((input) => {
        const currentValue = values[input.NAME] !== undefined ? values[input.NAME] : input.DEFAULT;

        if (input.TYPE === 'image') {
            const currentSource = sources[input.NAME] || 'noise';
            const currentFilter = textureSettings[input.NAME]?.filter || 'LINEAR';
            const currentWrap = textureSettings[input.NAME]?.wrap || 'REPEAT';

            return (
                <div key={input.NAME} className="space-y-2 border border-gray-800 p-2 rounded bg-gray-800/20">
                    <div className="flex justify-between items-baseline">
                        <label className="text-xs text-gray-400 block">{input.LABEL || input.NAME}</label>
                        <span className="text-[10px] text-gray-600 uppercase tracking-wider">Input & Texturing</span>
                    </div>

                    {/* Source Selection */}
                    <div className="flex gap-1 mb-2">
                        <button 
                            onClick={() => onSourceChange(input.NAME, 'noise')}
                            className={`flex-1 p-2 rounded text-xs flex flex-col items-center gap-1 transition-colors ${currentSource === 'noise' ? 'bg-cyan-900/50 text-cyan-200 border border-cyan-700' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
                            title="Procedural Noise"
                        >
                            <Sparkles size={14} />
                            <span>Noise</span>
                        </button>
                        <button 
