                                <button 
                                    onClick={() => onTextureSettingChange(input.NAME, { filter: 'NEAREST' })}
                                    className={`flex-1 p-1.5 rounded text-[10px] flex items-center justify-center gap-2 transition-colors ${currentFilter === 'NEAREST' ? 'bg-gray-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}
                                    title="Nearest Neighbor (Pixelated)"
                                >
                                    <Grid3X3 size={10} />
                                    Pixel
                                </button>
                             </div>
                        </div>

                        <div className="space-y-1">
                             <span className="text-[8px] text-gray-600 uppercase font-bold px-1">Wrap</span>
                             <div className="flex gap-1">
                                <button 
                                    onClick={() => onTextureSettingChange(input.NAME, { wrap: 'REPEAT' })}
                                    className={`flex-1 p-1.5 rounded text-[10px] flex items-center justify-center gap-2 transition-colors ${currentWrap === 'REPEAT' ? 'bg-gray-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}
                                    title="Repeat (Tiled)"
                                >
                                    <Repeat size={10} />
