import { GoogleGenAI } from "@google/genai";
import { cleanISFCode } from "../utils/isf";

const SYSTEM_INSTRUCTION = `
You are a World-Class Graphics Engineer and GLSL Architect specializing in the Interactive Shader Format (ISF) for VDMX6.
Your goal is to generate professional-grade, performant, and visually stunning generative visuals.

Standard ISF Requirements:
1. Every shader MUST begin with a multi-line comment /* ... */ containing a valid JSON object.
2. The JSON MUST define "INPUTS" which are exposed as uniforms in the host (VDMX6).
3. Do NOT declare 'uniform float name;' for any variable defined in the JSON INPUTS. The ISF host provides these automatically.
4. Use 'gl_FragColor' for the output.
5. Use 'isf_FragNormCoord' for normalized UVs (0.0 to 1.0).
6. Support 'TIME' and 'RENDERSIZE' as standard built-ins.

Creative Directives:
- Prefer procedural techniques: Raymarching, Signed Distance Fields (SDFs), Fractal Brownian Motion (FBM), and Voronoi noise.
- When "Audio Reactive" is requested, use 'AUDIO_SPECTRUM' (128x1 sampler2D) or 'AUDIO_VOL' (float).
- For professional results, include subtle chromatic aberration, bloom hints, or dithering where appropriate.
- Optimize for real-time performance (60 FPS).

Technical Mapping:
- 'vec2 MOUSE' (0..1)
- 'vec2 TILT' (-1..1)
- 'sampler2D AUDIO_SPECTRUM' (x=frequency, r=magnitude)
- 'float AUDIO_VOL' (Root Mean Square volume)

Always return the full code. No conversational filler.
`;

const REPAIR_INSTRUCTION = `
You are a Senior GLSL Debugger.
Your mission is to fix malformed ISF shaders.
- Fix JSON syntax in the header comment.
- Fix GLSL syntax errors (missing semicolons, type mismatches like float vs int).
- Ensure INPUTS in JSON are not redeclared in GLSL.
- Ensure the shader compiles on WebGL 1.0.
- Preserve the original creative logic while fixing the structural flaws.
`;

export const generateShader = async (prompt: string, style?: string, currentCode?: string): Promise<string> => {
  if (!process.env.API_KEY) throw new Error("API Key is missing");

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-pro-preview';

  let userPrompt = prompt;
  if (style) userPrompt = `Style: ${style}. Concept: ${prompt}`;
  if (currentCode) userPrompt = `Update this shader: ${prompt}\n\nExisting Code:\n${currentCode}`;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 4096 }, // High reasoning budget for pro code
        maxOutputTokens: 8192,
      },
    });

    let text = response.text || "";
    text = text.replace(/^```glsl\s*/i, '').replace(/^```\s*/, '').replace(/```$/, '').trim();
    return cleanISFCode(text);
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

export const repairShader = async (code: string, errorHint?: string): Promise<string> => {
    if (!process.env.API_KEY) throw new Error("API Key is missing");

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
    Analyze and repair this ISF shader.
    ${errorHint ? `Reported Error: ${errorHint}` : 'Perform general validation.'}

    BROKEN CODE:
    ${code}
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                systemInstruction: REPAIR_INSTRUCTION,
                thinkingConfig: { thinkingBudget: 2048 },
            }
        });

        let text = response.text || "";
        text = text.replace(/^```glsl\s*/i, '').replace(/^```\s*/, '').replace(/```$/, '').trim();
        return cleanISFCode(text);
    } catch (error) {
        console.error("Gemini Repair Error", error);
        throw error;
    }
};

