import { GoogleGenAI } from "@google/genai";
import { cleanISFCode } from "../utils/isf";

const SYSTEM_INSTRUCTION = `
You are a World-Class Graphics Engineer and GLSL Architect specializing in the Interactive Shader Format (ISF) for VDMX6.
Your goal is to generate professional-grade, performant, and visually stunning generative visuals.

CRITICAL TECHNICAL CONSTRAINTS (WebGL 1.0):
1. **NO** '#version' directives.
2. **NO** 'switch' statements. Use if/else chains.
3. **NO** dynamic array indexing. Loop indices must be constant or unrolled.
4. **NO** 'textureSize()'. Use standard 'RENDERSIZE' uniform.
5. **NO** non-square matrices (e.g., mat2x3) if possible.
6. **Output**: Use 'gl_FragColor'.

Standard ISF Structure:
1. START with a multi-line comment /* ... */ containing a VALID JSON object.
2. The JSON MUST define "INPUTS".
3. Do NOT declare 'uniform float name;' for any variable defined in the JSON INPUTS.
4. Use 'isf_FragNormCoord' for normalized UVs (0.0 to 1.0).

Creative Directives:
- Prefer procedural techniques: Raymarching, SDFs, FBM, Voronoi.
- When "Audio Reactive" is requested, use 'AUDIO_SPECTRUM' (128x1 sampler2D) or 'AUDIO_VOL'.
- Add "cinematic" polish: Vignette, noise grain, chromatic aberration.

Technical Mapping:
- 'vec2 MOUSE' (0..1)
- 'vec2 TILT' (-1..1)
- 'sampler2D AUDIO_SPECTRUM' (x=frequency, r=magnitude)
- 'float AUDIO_VOL' (0..1)

Always return the full code. No conversational filler.
`;

const REPAIR_INSTRUCTION = `
You are a Senior GLSL Debugger.
Your mission is to fix malformed ISF shaders.
1. FIX JSON syntax in the header comment (ensure valid JSON).
2. FIX GLSL syntax errors (missing semicolons, type mismatches float vs int).
3. REMOVE duplicate uniform declarations if they exist in JSON INPUTS.
4. CONVERT WebGL 2 features (switch, textureSize) to WebGL 1 compatible code.
5. Ensure main() exists and writes to gl_FragColor.
6. RETURN ONLY THE FIXED CODE.
`;

export const generateShader = async (prompt: string, style?: string, currentCode?: string): Promise<string> => {
  if (!process.env.API_KEY) throw new Error("API Key is missing");

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-pro-preview';

  let userPrompt = prompt;
  if (style) userPrompt = `Style: ${style}. Concept: ${prompt}`;
  if (currentCode) userPrompt = `Update this shader: ${prompt}\n\nExisting Code:\n${currentCode}`;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 4096 }, 
        maxOutputTokens: 8192,
      },
    });

    let text = response.text || "";
    text = text.replace(/^```glsl\s*/i, '').replace(/^```\s*/, '').replace(/```$/, '').trim();
    return cleanISFCode(text);
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

export const repairShader = async (code: string, errorHint?: string): Promise<string> => {
    if (!process.env.API_KEY) throw new Error("API Key is missing");

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
    Analyze and repair this ISF shader.
    ${errorHint ? `Reported Compiler Error: ${errorHint}` : 'Perform general validation and fix potential WebGL 1.0 issues.'}

    BROKEN CODE:
    ${code}
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                systemInstruction: REPAIR_INSTRUCTION,
                thinkingConfig: { thinkingBudget: 2048 },
            }
        });

        let text = response.text || "";
        text = text.replace(/^```glsl\s*/i, '').replace(/^```\s*/, '').replace(/```$/, '').trim();
        return cleanISFCode(text);
    } catch (error) {
        console.error("Gemini Repair Error", error);
        throw error;
    }
};

