                    <button onClick={() => {
                        const exists = favorites.find(f => f.code === code);
                        if(exists) setFavorites(p => p.filter(f => f.code !== code));
                        else setFavorites(p => [{ id: crypto.randomUUID(), timestamp: Date.now(), prompt: prompt || 'User Creation', code }, ...p]);
                    }} className={favorites.find(f => f.code === code) ? 'text-yellow-400' : 'hover:text-yellow-400'}>
                        <Star size={16} fill={favorites.find(f => f.code === code) ? 'currentColor' : 'none'} />
