  Monitor, Maximize, Image as ImageIcon, Sparkles, Layers, Box, Zap, X
} from 'lucide-react';
import { generateShader, repairShader } from './services/gemini';
import { parseISF } from './utils/isf';
import { DEFAULT_SHADER } from './constants';
import ShaderCanvas from './components/ShaderCanvas';
import Controls from './components/Controls';
import { ParsedShader, UniformValues, TextureSettings } from './types';
import { useMedia } from './hooks/useMedia';

const STYLES = [
  { id: 'none', label: 'Raw', icon: <Zap size={14} /> },
  { id: 'organic', label: 'Organic', icon: <Sparkles size={14} /> },
  { id: 'geometric', label: 'Geo', icon: <Box size={14} /> },
  { id: 'raymarched', label: '3D', icon: <Layers size={14} /> },
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>('Liquid chrome ripples responding to bass');
  const [selectedStyle, setSelectedStyle] = useState('organic');
  const [code, setCode] = useState<string>(DEFAULT_SHADER);
  const [refImage, setRefImage] = useState<string | null>(null);

  // History
  const [history, setHistory] = useState<string[]>([DEFAULT_SHADER]);
  const [historyIndex, setHistoryIndex] = useState(0);

  // Parsing & State
  const [parsedShader, setParsedShader] = useState<ParsedShader>(parseISF(DEFAULT_SHADER));
  const [uniforms, setUniforms] = useState<UniformValues>({});
  const [inputSources, setInputSources] = useState<Record<string, string>>({});
  const [textureSettings] = useState<TextureSettings>({}); 

  // UI State
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showCode, setShowCode] = useState(false);
  const [compileError, setCompileError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Refs
  const canvasContainerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Media Hooks
  const { 
    isWebcamActive, toggleWebcam, videoElement,
    isMicActive, toggleMic, audioVolume, audioDataArray
  } = useMedia();

  // Mouse tracking
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });
  const handleMouseMove = (e: React.MouseEvent) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    setMousePos({ 
        x: (e.clientX - rect.left) / rect.width, 
        y: 1.0 - (e.clientY - rect.top) / rect.height 
    });
  };

  // Code Update & History
  const updateCode = (newCode: string, addToHistory = true) => {
      setCode(newCode);
      if (addToHistory) {
          const newHistory = history.slice(0, historyIndex + 1);
          newHistory.push(newCode);
          setHistory(newHistory);
          setHistoryIndex(newHistory.length - 1);
      }
  };

  const handleUndo = () => historyIndex > 0 && updateCode(history[historyIndex-1], false);
  const handleRedo = () => historyIndex < history.length - 1 && updateCode(history[historyIndex+1], false);

  // Parser Effect
  useEffect(() => {
    const parsed = parseISF(code);
    setParsedShader(parsed);
    if (parsed.metadata?.INPUTS) {
      setUniforms(prev => {
          const next = { ...prev };
          parsed.metadata!.INPUTS.forEach(i => {
              if (next[i.NAME] === undefined) next[i.NAME] = i.DEFAULT;
          });
          return next;
      });
    }
  }, [code]);

  // Generation
  const handleGenerate = async () => {
    if (!prompt && !refImage) return;
    setIsGenerating(true);
    setError(null);
    try {
      const newCode = await generateShader(
          prompt, 
          selectedStyle !== 'none' ? selectedStyle : undefined,
          undefined,
          refImage || undefined // Pass reference image if it exists
      );
      updateCode(newCode);
    } catch (err: any) {
      setError(err.message || "Synthesis failed");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    const blob = new Blob([code], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Aether_ISF_${Date.now()}.fs`;
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
  };

  const handleRefImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onload = (ev) => setRefImage(ev.target?.result as string);
          reader.readAsDataURL(file);
      }
  };

  return (
    <div className="flex h-screen bg-[#050505] text-gray-200 font-sans overflow-hidden">

      {/* Sidebar - Simple & Functional */}
      <div className="w-80 flex flex-col border-r border-white/5 bg-[#0a0a0a] z-20 shadow-2xl">

        {/* Generator Header */}
        <div className="p-5 border-b border-white/5 bg-[#0a0a0a]">
            <div className="flex items-center justify-between mb-4">
                <h1 className="text-sm font-bold tracking-widest text-white uppercase">Aether <span className="text-cyan-500">ISF</span></h1>
                <div className="flex gap-1">
                     <button onClick={handleUndo} disabled={historyIndex === 0} className="p-1.5 hover:bg-white/5 rounded disabled:opacity-30 text-gray-500 hover:text-white transition-colors"><ChevronLeft size={14}/></button>
                     <button onClick={handleRedo} disabled={historyIndex === history.length - 1} className="p-1.5 hover:bg-white/5 rounded disabled:opacity-30 text-gray-500 hover:text-white transition-colors"><ChevronRight size={14}/></button>
                </div>
            </div>

            <div className="relative group mb-3">
                 <textarea 
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleGenerate(); }}}
                    className={`w-full bg-[#111] border border-white/10 rounded-lg p-3 text-xs focus:border-cyan-500/50 outline-none resize-none text-gray-300 placeholder:text-gray-700 transition-all ${refImage ? 'h-16 rounded-b-none border-b-0' : 'h-24'}`}
                    placeholder="Describe a visual effect..." 
                />

                {refImage && (
                    <div className="relative h-16 w-full bg-[#111] border border-white/10 border-t-0 rounded-b-lg overflow-hidden flex items-center justify-center">
                        <img src={refImage} alt="Reference" className="w-full h-full object-cover opacity-50" />
                        <div className="absolute inset-0 flex items-center justify-center gap-2">
                             <span className="text-[10px] uppercase font-bold text-white shadow-black drop-shadow-md">Image Ref</span>
                             <button onClick={() => setRefImage(null)} className="p-1 bg-black/50 hover:bg-red-500/80 rounded text-white transition-colors"><X size={12}/></button>
                        </div>
                    </div>
                )}

                <div className="absolute bottom-2 right-2 flex gap-1">
                    <button 
                        onClick={() => fileInputRef.current?.click()} 
                        className={`p-1.5 rounded transition-colors ${refImage ? 'bg-cyan-500/20 text-cyan-400' : 'bg-white/5 text-gray-500 hover:text-white'}`}
                        title="Upload Reference Image"
                    >
                        <ImageIcon size={14} />
                    </button>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleRefImageUpload} />
                </div>
            </div>

            <div className="flex gap-2 mb-3">
                {STYLES.map(s => (
                    <button 
                        key={s.id}
                        onClick={() => setSelectedStyle(s.id)}
                        className={`flex-1 py-1.5 rounded flex items-center justify-center gap-1.5 text-[10px] uppercase font-bold tracking-wider transition-all ${selectedStyle === s.id ? 'bg-cyan-900/30 text-cyan-400 border border-cyan-500/30' : 'bg-white/5 text-gray-500 hover:bg-white/10'}`}
                        title={s.label}
                    >
                        {s.icon}
                    </button>
                ))}
            </div>

            <button 
                onClick={handleGenerate} 
                disabled={isGenerating}
                className="w-full py-2.5 bg-gradient-to-r from-cyan-600 to-blue-600 hover:from-cyan-500 hover:to-blue-500 text-white rounded-md text-xs font-bold uppercase tracking-widest shadow-lg shadow-cyan-900/20 flex items-center justify-center gap-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
                {isGenerating ? <RefreshCw className="animate-spin" size={14} /> : <Wand2 size={14} />}
                Generate
            </button>

            {error && <div className="mt-2 text-[10px] text-red-400 bg-red-900/10 p-2 rounded border border-red-900/20">{error}</div>}
        </div>

        {/* Parameters Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#080808]">
            {compileError && (
                <div className="p-3 bg-red-500/10 border-b border-red-500/20">
                     <div className="flex items-center justify-between text-red-400 mb-1">
                        <span className="text-[10px] font-bold uppercase">Shader Error</span>
                        <button onClick={() => repairShader(code, compileError).then(updateCode)} className="text-[9px] underline hover:text-red-300">Auto-Fix</button>
                     </div>
                     <p className="text-[9px] font-mono opacity-70 line-clamp-2">{compileError}</p>
                </div>
            )}
            <Controls 
                metadata={parsedShader.metadata}
                values={uniforms}
                sources={inputSources}
                onChange={(n, v) => setUniforms(p => ({...p, [n]: v}))}
                onSourceChange={(n, s) => setInputSources(p => ({...p, [n]: s}))}
                onImageUpload={(n, f) => setInputSources(p => ({...p, [n]: URL.createObjectURL(f)}))}
            />
        </div>

        {/* Functional Footer */}
        <div className="p-3 bg-[#0a0a0a] border-t border-white/5 grid grid-cols-2 gap-2">
             <button onClick={handleDownload} className="flex items-center justify-center gap-2 py-2 bg-white/5 hover:bg-white/10 text-white/70 hover:text-white rounded text-xs font-bold transition-all border border-white/5">
                <Download size={14} /> Export
             </button>
             <button onClick={() => setShowCode(!showCode)} className={`flex items-center justify-center gap-2 py-2 rounded text-xs font-bold transition-all border ${showCode ? 'bg-cyan-900/20 text-cyan-400 border-cyan-500/30' : 'bg-white/5 hover:bg-white/10 text-white/70 border-white/5'}`}>
                <Monitor size={14} /> Code
             </button>
        </div>
      </div>

      {/* Main Canvas Area */}
      <div className="flex-1 flex flex-col relative bg-black group">

         {/* Hover Controls */}
         <div className="absolute top-4 right-4 z-10 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
             <button onClick={toggleMic} className={`p-2 rounded-full backdrop-blur-md border ${isMicActive ? 'bg-red-500/20 border-red-500/50 text-red-400' : 'bg-black/40 border-white/10 text-white/40 hover:text-white'}`}>
                {isMicActive ? <Mic size={16} /> : <MicOff size={16} />}
             </button>
             <button onClick={toggleWebcam} className={`p-2 rounded-full backdrop-blur-md border ${isWebcamActive ? 'bg-green-500/20 border-green-500/50 text-green-400' : 'bg-black/40 border-white/10 text-white/40 hover:text-white'}`}>
                {isWebcamActive ? <Video size={16} /> : <VideoOff size={16} />}
             </button>
             <button onClick={() => canvasContainerRef.current?.requestFullscreen()} className="p-2 rounded-full bg-black/40 backdrop-blur-md border border-white/10 text-white/40 hover:text-white">
                <Maximize size={16} />
             </button>
         </div>

         {/* Canvas */}
         <div ref={canvasContainerRef} className="flex-1 relative flex items-center justify-center bg-black overflow-hidden" onMouseMove={handleMouseMove}>
             <ShaderCanvas 
                parsedShader={parsedShader}
                uniforms={uniforms}
                sources={inputSources}
                textureSettings={textureSettings}
                videoElement={videoElement}
                audioVolume={audioVolume}
                audioDataArray={audioDataArray}
                mouse={mousePos}
                tilt={{x:0, y:0}}
                onCompileError={setCompileError}
                onCanvasRef={r => canvasRef.current = r}
             />
         </div>

         {/* Code View */}
         {showCode && (
             <div className="h-1/3 border-t border-white/10 bg-[#080808] flex flex-col animate-in slide-in-from-bottom-10">
                 <div className="flex justify-between items-center px-4 py-2 border-b border-white/5 bg-[#0a0a0a]">
                     <span className="text-[10px] font-mono text-white/30 uppercase">GLSL Source</span>
                     <button onClick={() => { navigator.clipboard.writeText(code); setCopied(true); setTimeout(()=>setCopied(false), 2000); }} className="text-white/30 hover:text-cyan-400">
                        {copied ? <Check size={14} /> : <Copy size={14} />}
                     </button>
                 </div>
                 <textarea 
                    value={code} 
                    onChange={e => updateCode(e.target.value)} 
                    spellCheck={false}
                    className="flex-1 bg-transparent p-4 font-mono text-xs text-gray-400 outline-none resize-none leading-relaxed"
                 />
             </div>
         )}
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { cleanISFCode } from "../utils/isf";

const SYSTEM_INSTRUCTION = `
You are a World-Class Graphics Engineer and GLSL Architect specializing in the Interactive Shader Format (ISF) for VDMX6.
Your goal is to generate professional-grade, performant, and visually stunning generative visuals that drop directly into VDMX.

CRITICAL VDMX / ISF SPECIFICATIONS:
1. **JSON Header**: MUST be valid JSON inside /* ... */.
   - "ISFVSN": "2.0"
   - "CATEGORIES": ["Generative", "Visuals", ...appropriate tags]
   - "INPUTS": Array of definitions.
2. **Inputs**:
   - Use "TYPE": "float", "bool", "long" (dropdown), "color", "point2D".
   - Do NOT use "event" type unless creating a trigger (map to bool).
3. **Coordinate Systems**:
   - Use 'isf_FragNormCoord' (provided macro) for UVs (0..1).
   - Use 'RENDERSIZE' (vec2) for screen dimensions.
4. **Macros & Compatibility**:
   - 'IMG_THIS_PIXEL(sampler)' fetches current UV from texture.
   - 'IMG_NORM_PIXEL(sampler, uv)' fetches at specific UV.
5. **Alpha**:
   - Ensure 'gl_FragColor.a = 1.0;' for opaque visuals. VDMX handles alpha blending; transparency might make the layer invisible if not intended.

TECHNICAL CONSTRAINTS (WebGL 1.0):
1. **NO** '#version' directives.
2. **NO** 'switch' statements. Use if/else.
3. **NO** dynamic array indexing.
4. **NO** 'textureSize()'.
5. **NO** non-square matrices (e.g. mat2x3).
6. **NO** redefining 'PI', 'TWO_PI', 'HALF_PI'. They are predefined.
7. **Single Pass Only**: Do not use "PASSES" or "PERSISTENT" buffers in JSON unless specifically asked (complex to preview on web).

Creative Directives:
- Create "Generative Art" suitable for VJing.
- Audio Reactivity: 'AUDIO_SPECTRUM' (sampler2D) and 'AUDIO_VOL' (float).
- Parameters: Expose useful variables (Speed, Scale, Color) in "INPUTS".
- **Image Reference**: If an image is provided, analyze its colors, shapes, patterns, and composition. Write a procedural shader that mathematically reproduces that aesthetic.

Output only the raw GLSL code with the JSON header.
`;

const REPAIR_INSTRUCTION = `
You are a Senior GLSL Debugger for VDMX6 ISF Shaders.
Your mission is to fix malformed ISF shaders.
1. FIX JSON syntax in the header comment.
2. FIX GLSL syntax errors (missing semicolons, type mismatches).
3. REMOVE duplicate uniform declarations if they exist in JSON INPUTS.
4. REMOVE definitions of PI, TWO_PI, HALF_PI (predefined).
5. CONVERT WebGL 2 features to WebGL 1.
6. Ensure 'isf_FragNormCoord' is used instead of manual gl_FragCoord division where possible.
7. Ensure main() writes to gl_FragColor.
8. RETURN ONLY THE FIXED CODE.
`;

const extractGLSL = (text: string): string => {
  if (!text) return "";

  // 1. Try to extract from markdown code blocks
  const codeBlockRegex = /```(?:glsl|c|cpp)?([\s\S]*?)```/i;
  const match = text.match(codeBlockRegex);
  if (match && match[1]) {
    return match[1].trim();
  }

  // 2. If no code blocks, check for ISF JSON start
  // ISF files almost always start with /* { ... } */
  const jsonStartIndex = text.indexOf('/*');
  if (jsonStartIndex > -1) {
    return text.substring(jsonStartIndex).trim();
  }

  // 3. Fallback: return raw text but try to strip common conversational prefixes if they exist at the very start
  // This is risky but helps if the model says "Here is the code:\n/*..." without markdown
  return text.replace(/^(Here is|Here's|Sure|Certainly).*?:\s*/is, '').trim();
};

export const generateShader = async (prompt: string, style?: string, currentCode?: string, referenceImage?: string): Promise<string> => {
  if (!process.env.API_KEY) throw new Error("API Key is missing");

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-pro-preview';

  let userPrompt = prompt;
  if (style) userPrompt = `Style: ${style}. Concept: ${prompt}`;
  if (currentCode) userPrompt = `Update this shader: ${prompt}\n\nExisting Code:\n${currentCode}`;
  if (referenceImage) userPrompt = `Look at this image. Create a procedural GLSL shader that visually replicates this image's style, colors, and patterns. ${prompt}`;

  let contents: any = userPrompt;

  // Handle Multimodal Input
  if (referenceImage) {
      const base64Data = referenceImage.split(',')[1];
      const mimeType = referenceImage.split(';')[0].split(':')[1];

      contents = [
          {
              inlineData: {
                  data: base64Data,
                  mimeType: mimeType
              }
          },
          { text: userPrompt }
      ];
  }

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 4096 }, 
        maxOutputTokens: 8192,
      },
    });

    const text = response.text || "";
    const extracted = extractGLSL(text);
    return cleanISFCode(extracted);
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

export const repairShader = async (code: string, errorHint?: string): Promise<string> => {
    if (!process.env.API_KEY) throw new Error("API Key is missing");

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
    Analyze and repair this ISF shader.
    ${errorHint ? `Reported Compiler Error: ${errorHint}` : 'Perform general validation and fix potential WebGL 1.0 issues.'}

    BROKEN CODE:
    ${code}
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                systemInstruction: REPAIR_INSTRUCTION,
                thinkingConfig: { thinkingBudget: 2048 },
            }
        });

        const text = response.text || "";
        const extracted = extractGLSL(text);
        return cleanISFCode(extracted);
    } catch (error) {
        console.error("Gemini Repair Error", error);
        throw error;
    }
};

import { ParsedShader, ISFMetadata, ISFInput } from '../types';

export const parseISF = (code: string): ParsedShader => {
  let metadata: ISFMetadata | null = null;
  const jsonRegex = /\/\*([\s\S]*?)\*\//;
  const match = code.match(jsonRegex);

  if (match && match[1]) {
    try {
      const parsed = JSON.parse(match[1].trim());
      if (typeof parsed === 'object') metadata = parsed as ISFMetadata;
    } catch (e) {
      console.warn("ISF Header Parse Error", e);
    }
  }

  return { rawCode: code, metadata, fragmentBody: code };
};

export const generateWebGLPreamble = (metadata: ISFMetadata | null): string => {
  let preamble = `
    precision mediump float;
    uniform float TIME;
    uniform int PASSINDEX;
    uniform vec4 DATE;
    uniform vec2 RENDERSIZE;
    uniform vec2 MOUSE;
    uniform float AUDIO_VOL;
    uniform vec2 TILT;
    uniform sampler2D AUDIO_SPECTRUM;

    // VDMX / ISF Standard Macros & Compatibility
    #define isf_FragNormCoord (gl_FragCoord.xy / RENDERSIZE)
    #define vv_FragNormCoord isf_FragNormCoord

    // Image sampling macros - Robust .xy selection
    #define IMG_NORM_PIXEL(sampler, coord) texture2D(sampler, coord)
    #define IMG_THIS_PIXEL(sampler) texture2D(sampler, isf_FragNormCoord)
    #define IMG_PIXEL(sampler, coord) texture2D(sampler, (coord).xy / RENDERSIZE)

    // Math Utilities
    #ifndef PI
    #define PI 3.14159265359
    #endif

    #ifndef TWO_PI
    #define TWO_PI 6.28318530718
    #endif

    #ifndef HALF_PI
    #define HALF_PI 1.57079632679
    #endif

    // Note: 'rot' macro removed to avoid collisions with user-defined functions
  `;

  if (metadata?.INPUTS) {
    const reserved = ['TIME', 'PASSINDEX', 'RENDERSIZE', 'DATE', 'MOUSE', 'AUDIO_VOL', 'TILT', 'AUDIO_SPECTRUM'];
    metadata.INPUTS.forEach((input: ISFInput) => {
      if (reserved.includes(input.NAME)) return;
      if (input.TYPE === 'float') preamble += `uniform float ${input.NAME};\n`;
      else if (input.TYPE === 'bool') preamble += `uniform bool ${input.NAME};\n`; 
      else if (input.TYPE === 'long') preamble += `uniform int ${input.NAME};\n`; 
      else if (input.TYPE === 'point2D') preamble += `uniform vec2 ${input.NAME};\n`;
      else if (input.TYPE === 'color') preamble += `uniform vec4 ${input.NAME};\n`;
      else if (input.TYPE === 'image') preamble += `uniform sampler2D ${input.NAME};\n`;
      else if (input.TYPE === 'event') preamble += `uniform bool ${input.NAME};\n`; // Handle events as bools
    });
  }

  return preamble;
};

export const cleanISFCode = (code: string): string => {
    let clean = code;

    // Remove #version directives (WebGL 1.0 does not support them in the way modern GLSL does, or conflicts with preamble)
    clean = clean.replace(/^\s*#version\s+.*$/gm, '// #version removed for WebGL 1.0 compatibility');

    // Remove precision declarations (handled in preamble)
    clean = clean.replace(/^\s*precision\s+\w+\s+float\s*;/gm, '');

    // Remove built-in uniforms that we provide
    const reserved = ['TIME', 'RENDERSIZE', 'MOUSE', 'AUDIO_VOL', 'TILT', 'AUDIO_SPECTRUM', 'PASSINDEX'];
    reserved.forEach(u => {
        const re = new RegExp(`^\\s*uniform\\s+\\w+\\s+${u}\\s*;`, 'gm');
        clean = clean.replace(re, '');
    });

    // Remove const/define PI collisions which cause "syntax error" when macro expands 'const float 3.14...'
    clean = clean.replace(/^\s*#define\s+(PI|TWO_PI|HALF_PI)\s+.*$/gm, '// $1 macro removed (predefined)');
    clean = clean.replace(/^\s*const\s+float\s+(PI|TWO_PI|HALF_PI)\s*=.*$/gm, '// $1 const removed (predefined)');

    return clean;
};

